import pandas as pd  # type: ignore
import matplotlib.pyplot as plt  # type: ignore
from pathlib import Path

# Resolve input and output locations relative to this script.
BASE_DIR = Path(__file__).resolve().parent
PROJECT_DIR = BASE_DIR.parent
CSV_FILE = BASE_DIR / "results_wrap.csv"
FIGURES_DIR = PROJECT_DIR / "documentation" / "figures"

# Create the figure output folder if it does not exist yet.
FIGURES_DIR.mkdir(parents=True, exist_ok=True)

# Load the wrap benchmark CSV generated by the batch file.
df = pd.read_csv(CSV_FILE)

# Build a readable label that also includes the wrap mode.
def label_row(row):
    base = "naive" if int(row["tiled"]) == 0 else f"tiled {int(row['lx'])}x{int(row['ly'])}"
    return f"{base} wrap={int(row['wrap'])}"

# Add helper columns used by the comparison chart.
df["label"] = df.apply(label_row, axis=1)
df["cells"] = df["rows"] * df["cols"]
df["size_label"] = df.apply(lambda r: f"{int(r['rows'])}x{int(r['cols'])}", axis=1)
df["kernel_per_iter_ms"] = df["kernel_ms"] / df["iters"]

# Define a stable x-axis order based on grid size.
size_order_df = (
    df[["rows", "cols", "cells", "size_label"]]
    .drop_duplicates()
    .sort_values(["cells", "rows", "cols"])
    .reset_index(drop=True)
)

size_order = size_order_df["size_label"].tolist()
size_to_x = {label: i for i, label in enumerate(size_order)}

# Keep the wrap comparison legend in a predictable order.
preferred_order = [
    "naive wrap=0",
    "naive wrap=1",
    "tiled 16x16 wrap=0",
    "tiled 16x16 wrap=1",
]

# Sort labels so matching configurations stay grouped together.
def sort_labels(labels):
    labels = list(labels)
    return sorted(
        labels,
        key=lambda x: (preferred_order.index(x) if x in preferred_order else 999, x)
    )

# Plot per-iteration kernel time for wrapped and non-wrapped runs.
plt.figure(figsize=(10, 6))
plt.rcParams.update({"font.size": 12})

for label in sort_labels(df["label"].unique()):
    grp = df[df["label"] == label].copy()
    grp["x"] = grp["size_label"].map(size_to_x)
    grp = grp.sort_values("x")

    plt.plot(
        grp["x"],
        grp["kernel_per_iter_ms"],
        marker="o",
        label=label
    )

    # Show the exact value above each plotted point.
    for _, row in grp.iterrows():
        plt.text(
            row["x"],
            row["kernel_per_iter_ms"] + 0.01,
            f"{row['kernel_per_iter_ms']:.3f}",
            ha="center",
            va="bottom",
            fontsize=9
        )

plt.xticks(range(len(size_order)), size_order)
plt.xlabel("Rácsméret")
plt.ylabel("Kernel idő / iteráció (ms)")
plt.title("OpenCL Game of Life - wrap összehasonlítás")
plt.legend()
plt.grid(True)
plt.tight_layout()
plt.savefig(FIGURES_DIR / "wrap_kernel_compare.png", dpi=300)
plt.close()

# Print the generated figure path for quick confirmation.
print(f"Kész: {FIGURES_DIR / 'wrap_kernel_compare.png'}")
